import './StoreLocator.css';

function StoreLocator() {
  const branches = [
    {
      name: 'Market Square GRA',
      address: '12 GRA Phase 2, Port Harcourt',
      phone: '0803 123 4567'
    },
    {
      name: 'Market Square PH Mall',
      address: 'Port Harcourt Mall, Aba Road',
      phone: '0803 234 5678'
    },
    {
      name: 'Market Square Old GRA',
      address: '35 Old GRA, Port Harcourt',
      phone: '0803 345 6789'
    }
  ];

  return (
    <div className="store-locator-page">
      <h2>Our Branches</h2>
      <div className="branch-list">
        {branches.map((branch, index) => (
          <div key={index} className="branch-card">
            <h3>{branch.name}</h3>
            <p>{branch.address}</p>
            <p>{branch.phone}</p>
          </div>
        ))}
      </div>

      <h3>Find Us On Map</h3>
      <div className="map-container">
        <iframe
          title="Market Square Location"
          src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d31631.197437789264!2d7.0073855!3d4.8177639!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x1069cd567c0b73cf%3A0xa47c81d1bb5c78ae!2sPort%20Harcourt%20Mall!5e0!3m2!1sen!2sng!4v1682629939640"
          width="100%"
          height="350"
          allowFullScreen=""
          loading="lazy"
          referrerPolicy="no-referrer-when-downgrade"
        ></iframe>
      </div>
    </div>
  );
}

export default StoreLocator;
